INSERT INTO supplemental_essays (id, college_id, prompt, word_limit) VALUES (gen_random_uuid(), (SELECT id FROM colleges WHERE full_name = 'Georgetown University'), 'As Georgetown is a diverse community, the Admissions Committee would like to know more about you in your own words. Please submit a brief personal or creative essay which you feel best describes you and reflects on your own background, identity, skills, and talents.', Unknown);
INSERT INTO supplemental_essays (id, college_id, prompt, word_limit) VALUES (gen_random_uuid(), (SELECT id FROM colleges WHERE full_name = 'Georgetown University'), 'A liberal arts education from the College of Arts & Sciences involves encounters with new concepts and modes of inquiry. Describe something (a class, a book, an event, etc.) that changed your thinking. (Applicants to the sciences, mathematics, public policy or languages are encouraged to include examples related to that field.)', Unknown);
